<x-layouts.app :title="$order->exists?'Edit Work Order':'Create Work Order'"><form method="post" action="{{ $order->exists?route('work-orders.update',$order):route('work-orders.store') }}" class="card grid gap-4 p-6 md:grid-cols-2">@csrf @if($order->exists)@method('put')@endif<label>Title<input name="title" value="{{ old('title',$order->title) }}" class="input mt-1 w-full"></label><label>Asset<select name="asset_id" class="input mt-1 w-full">@foreach($assets as $a)<option value="{{ $a->id }}" @selected($order->asset_id===$a->id)>{{ $a->name }}</option>@endforeach</select></label><label>Technician<select name="technician_id" class="input mt-1 w-full">@foreach($users as $u)<option value="{{ $u->id }}" @selected($order->technician_id===$u->id)>{{ $u->name }}</option>@endforeach</select></label><label>Priority<select name="priority" class="input mt-1 w-full">@foreach($priorities as $p)<option value="{{ $p->value }}" @selected($order->priority?->value===$p->value)>{{ $p->label() }}</option>@endforeach</select></label><label>Status<select name="status" class="input mt-1 w-full">@foreach($statuses as $s)<option value="{{ $s->value }}" @selected($order->status?->value===$s->value)>{{ $s->label() }}</option>@endforeach</select></label><label>Due Date<input type="date" name="due_date" value="{{ old('due_date',$order->due_date?->format('Y-m-d')) }}" class="input mt-1 w-full"></label><label class="md:col-span-2">Description<textarea name="description" class="input mt-1 w-full">{{ old('description',$order->description) }}</textarea></label><button class="btn md:col-span-2">Save Work Order</button></form></x-layouts.app>
